def recommend_method(n_atoms, accuracy_needed, state_type='valence'):
    """Recommend an excited state calculation method."""

    # Base recommendations by accuracy
    accuracy_methods = {
        'qualitative': {'method': 'CIS', 'error': '~1 eV', 'limit': 1000},
        'semi-quantitative': {'method': 'TDDFT/B3LYP', 'error': '~0.3 eV', 'limit': 200},
        'quantitative': {'method': 'EOM-CCSD', 'error': '~0.1-0.2 eV', 'limit': 30},
        'benchmark': {'method': 'EOM-CC3', 'error': '~0.05 eV', 'limit': 15},
    }

    base = accuracy_methods.get(accuracy_needed, accuracy_methods['semi-quantitative'])

    # Adjust for system size
    if n_atoms > base['limit']:
        # Fall back to cheaper method
        if accuracy_needed == 'quantitative' and n_atoms <= 100:
            base = {'method': 'ADC(2)', 'error': '~0.2-0.3 eV', 'limit': 100}
        else:
            base = {'method': 'TDDFT', 'error': '~0.3 eV', 'limit': 200}

    # Adjust for state type
    notes = ''
    if state_type == 'CT':
        if 'TDDFT' in base['method']:
            base['method'] = 'TDDFT/CAM-B3LYP'
            notes = 'Range-separated functional for charge-transfer'
    elif state_type == 'rydberg':
        notes = 'Use augmented basis set (aug-cc-pVDZ or larger)'
    elif state_type == 'doubly-excited':
        if n_atoms <= 15:
            base = {'method': 'CASPT2 or EOM-CCSDT', 'error': '~0.1 eV', 'limit': 15}
        else:
            base = {'method': 'SF-TDDFT or ADC(2)-x', 'error': '~0.3 eV', 'limit': 50}
        notes = 'Standard methods miss double excitations'

    base['notes'] = notes
    return base

# Test
test_cases = [
    (100, 'semi-quantitative', 'valence'),
    (15, 'quantitative', 'valence'),
    (30, 'semi-quantitative', 'CT'),
    (10, 'benchmark', 'doubly-excited'),
]

for n_atoms, accuracy, state_type in test_cases:
    result = recommend_method(n_atoms, accuracy, state_type)
    print(f"\n{n_atoms} atoms, {accuracy}, {state_type}:")
    print(f"  Method: {result['method']}")
    print(f"  Error: {result['error']}")
